#nullable enable // autogenerated

using System.Linq;
using System.Text;
using MVZ2.Vanilla.Localization;
using MVZ2Logic;
using MVZ2Logic.Commands;
using MVZ2Logic.Definitions;
using MVZ2Logic.Localization;
using PVZEngine;

namespace MVZ2.GameContent.Commands
{
    [AutoCommandDefinition(VanillaCommandNames.unlock)]
    public class Unlock : CommandDefinition
    {
        public Unlock(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Invoke(string[] parameters)
        {
            var game = Global.Game;
            var saves = Global.Saves;

            if (parameters[0] == "add")
            {
                var id = NamespaceID.Parse(parameters[1], Global.BuiltinNamespace);
                if (!saves.IsUnlocked(id))
                {
                    saves.Unlock(id);
                    saves.SaveToFile();
                    PrintLine(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_UNLOCK_ADD_SUCCESS, LogicStrings.CONTEXT_COMMAND_OUTPUT, id.ToString()));
                }
                else
                {
                    PrintLine(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_UNLOCK_ADD_FAILED_ALREADY_UNLOCKED, LogicStrings.CONTEXT_COMMAND_OUTPUT, id.ToString()));
                }
            }
            else if (parameters[0] == "remove")
            {
                var id = NamespaceID.Parse(parameters[1], Global.BuiltinNamespace);
                if (saves.IsUnlocked(id))
                {
                    saves.Relock(id);
                    saves.SaveToFile();
                    PrintLine(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_UNLOCK_REMOVE_SUCCESS, LogicStrings.CONTEXT_COMMAND_OUTPUT, id.ToString()));
                }
                else
                {
                    PrintLine(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_UNLOCK_REMOVE_FAILED_NOT_UNLOCKED, LogicStrings.CONTEXT_COMMAND_OUTPUT, id.ToString()));
                }
            }
            else if (parameters[0] == "list")
            {
                StringBuilder sb = new StringBuilder();
                foreach (var id in saves.GetAllUnlocks())
                {
                    sb.AppendLine(id.ToString());
                }
                Print(sb.ToString());
            }
            else if (parameters[0] == "listlocked")
            {
                StringBuilder sb = new StringBuilder();
                foreach (var id in game.GetAllUnlockConditions().Except(saves.GetAllUnlocks()))
                {
                    sb.AppendLine(id.ToString());
                }
                Print(sb.ToString());
            }
            else if (parameters[0] == "all")
            {
                var currentUnlocks = saves.GetAllUnlocks();
                var allUnlocks = game.GetAllUnlockConditions();
                var unlocks = allUnlocks.Except(currentUnlocks);
                if (unlocks.Count() <= 0)
                {
                    PrintLine(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_UNLOCK_ALL_FAILED_NOTHING_LOCKED, LogicStrings.CONTEXT_COMMAND_OUTPUT));
                }
                else
                {
                    StringBuilder sb = new StringBuilder();
                    foreach (var id in unlocks)
                    {
                        saves.Unlock(id);
                        sb.AppendLine(id.ToString());
                    }
                    saves.SaveToFile();
                    PrintLine(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_UNLOCK_ALL_SUCCESS, LogicStrings.CONTEXT_COMMAND_OUTPUT, sb.ToString()));
                }
            }
            else if (parameters[0] == "none")
            {
                var unlocks = saves.GetAllUnlocks();
                if (unlocks.Length <= 0)
                {
                    PrintLine(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_UNLOCK_NONE_FAILED_NOTHING_UNLOCKED, LogicStrings.CONTEXT_COMMAND_OUTPUT));
                }
                else
                {
                    StringBuilder sb = new StringBuilder();
                    foreach (var id in unlocks)
                    {
                        saves.Relock(id);
                        sb.AppendLine(id.ToString());
                    }
                    saves.SaveToFile();
                    PrintLine(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_UNLOCK_NONE_SUCCESS, LogicStrings.CONTEXT_COMMAND_OUTPUT, sb.ToString()));
                }
            }
        }
    }
}